features.snippet:
always_ff @(posedge clk, negedge rst_n) begin
  if (rst_n == 1'b0) begin
    exc_ctrl_cs <= IDLE;
  end else begin
    unique case (1'b1)
      ctrl_ack_i: exc_ctrl_cs <= IRQ_DONE;
      ctrl_kill_i: exc_ctrl_cs <= IDLE;
      default: exc_ctrl_cs <= IRQ_PENDING;
    endcase
  end
end

enum logic [1:0] { IDLE, IRQ_PENDING, IRQ_DONE } exc_ctrl_cs;
always_ff @(posedge clk, negedge rst_n) begin
  if (rst_n == 1'b0) exc_ctrl_cs <= IDLE;
  else unique case (exc_ctrl_cs) IDLE: ... IRQ_PENDING: ... IRQ_DONE: ... endcase
end
